// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MAX_N 100
#define MAX_K 1000
#define MAX_M 10000
#define EPS 1e-9

int main() {
    int n, k, m;
    double evaporation[MAX_N];
    int reactions[MAX_M][4];
    double amounts[MAX_N][MAX_K];
    double new_amounts[MAX_N][MAX_K];
    int t = 0;
    double total_amounts[MAX_N] = {0};

    // Read input
    scanf("%d %d", &n, &k);
    for (int i = 0; i < n; i++) {
        scanf("%lf", &evaporation[i]);
    }
    scanf("%d", &m);
    for (int i = 0; i < m; i++) {
        scanf("%d %d %lf %d", &reactions[i][0], &reactions[i][1], &reactions[i][2], &reactions[i][3]);
    }

    // Initialize amounts
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < k; j++) {
            amounts[i][j] = (i == 0 && j == 0) ? 1.0 : 0.0;
        }
    }

    // Simulate reactions
    while (1) {
        double total_amount = 0.0;
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < k; j++) {
                total_amount += amounts[i][j];
            }
        }
        if (total_amount < EPS) break;

        // Evaporation
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < k; j++) {
                new_amounts[i][j] = amounts[i][j] * (1.0 - evaporation[i]);
            }
        }

        // Reactions
        for (int i = 0; i < m; i++) {
            int a = reactions[i][0];
            int b = reactions[i][1];
            double r = reactions[i][2];
            int s = reactions[i][3];
            for (int j = 0; j < k; j++) {
                if (s == 0) {
                    new_amounts[b][j] += new_amounts[a][j] * r;
                } else {
                    new_amounts[b][(j + 1) % k] += new_amounts[a][j] * r;
                }
            }
        }

        // Update amounts
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < k; j++) {
                amounts[i][j] = new_amounts[i][j];
                total_amounts[i] += amounts[i][j];
            }
        }
        t++;
    }

    // Print results
    for (int i = 0; i < n; i++) {
        printf("%.6f ", total_amounts[i]);
    }
    printf("\n");
    return 0;
}

